+{
+    asx_auto_deadline_tracker dt;
+    asx_auto_deadline_init(&dt);
+
+    /* Task completes at t=800, deadline at t=1000 → hit */
+    asx_auto_deadline_record(&dt, 1000, 800);
+
+    ASSERT_EQ(dt.total_deadlines, 1u);
+    ASSERT_EQ(dt.deadline_hits, 1u);
