+    asx_auto_deadline_record(&dt, 1000, 1200);
+
+    ASSERT_EQ(dt.total_deadlines, 1u);
+    ASSERT_EQ(dt.deadline_hits, 0u);
+    ASSERT_EQ(dt.deadline_misses, 1u);
