+{
+    asx_auto_deadline_tracker dt;
+    uint32_t i;
+
+    asx_auto_deadline_init(&dt);
+
+    /* 8 hits, 2 misses → 20% miss rate = 2000 in pct*100 */
+    for (i = 0; i < 8; i++) {
+        asx_auto_deadline_record(&dt, 1000, 500 + i * 10);
+    }
+    for (i = 0; i < 2; i++) {
+        asx_auto_deadline_record(&dt, 1000, 1100 + i * 10);
+    }
