+
+    /* Oldest should be entry 10 (first 10 were overwritten) */
+    oldest = asx_auto_audit_get(&ring, 0);
+    ASSERT_TRUE(oldest != NULL);
+    ASSERT_EQ(oldest->entity_id, (uint64_t)10);
