+    /* Region 1 takes half */
+    for (i = 0; i < half; i++) {
+        ASSERT_EQ(asx_task_spawn(r1, poll_ok, NULL, &tid), ASX_OK);
+    }
+
+    /* Region 2 takes the rest */
