+
+    asx_hft_jitter_init(&jt, 0);  /* recompute every sample */
+
+    /* All same value (0) — bin midpoint equals mean, so MAD = 0 */
+    for (i = 0; i < 100; i++) {
+        asx_hft_jitter_record(&jt, 0);
