+
+    /* Half at 10ns, half at 10000ns — should have nonzero jitter */
+    for (i = 0; i < 50; i++) {
+        asx_hft_jitter_record(&jt, 10);
+    }
+    for (i = 0; i < 50; i++) {
+        asx_hft_jitter_record(&jt, 10000);
+    }
