+        ASSERT_EQ(asx_scheduler_run(rid, &budget),
+                  ASX_E_POLL_BUDGET_EXHAUSTED);
+    }
+
+    /* Give more budget — still pending, should exhaust again */
+    {
+        asx_budget budget = asx_budget_from_polls(10);
+        ASSERT_EQ(asx_scheduler_run(rid, &budget),
